css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #ffffff; color: #1a1a1a; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; border-bottom: 1px solid #f0f0f0; }
.brand { font-size: 22px; font-weight: 900; letter-spacing: 0.1em; }
.nav-links { display: flex; gap: 30px; }
.nav-links a { color: #999; text-decoration: none; font-size: 13.5px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.03em; }
.nav-links a.active { color: #1a1a1a; }
.nav-icons { display: flex; gap: 20px; font-size: 18px; }
.cart-icon { position: relative; cursor: pointer; }
.cart-count { position: absolute; top: -8px; right: -10px; background: #1a1a1a; color: white; font-size: 10px; font-weight: 800; width: 18px; height: 18px; border-radius: 50%; display: flex; align-items: center; justify-content: center; }
.hero { padding: 70px 60px; background: linear-gradient(135deg, #fdf2f8, #fff7ed); }
.hero-text { max-width: 600px; }
.badge { display: inline-block; color: #ec4899; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 20px; }
.hero h1 { font-size: 46px; font-weight: 800; line-height: 1.3; margin-bottom: 18px; }
.hero h1 span { color: #ec4899; }
.hero p { color: #888; font-size: 15px; line-height: 1.7; margin-bottom: 28px; }
.btn-primary { background: #1a1a1a; color: white; border: none; padding: 15px 32px; font-size: 13.5px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; cursor: pointer; }
.btn-primary.full { width: 100%; }
.products { padding: 50px 60px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 30px; flex-wrap: wrap; }
.filter { background: #f7f7f7; border: none; color: #999; padding: 10px 20px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: #1a1a1a; color: white; }
.product-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 24px; }
.product-card { cursor: pointer; }
.product-img { aspect-ratio: 3/4; background: #f7f7f7; border-radius: 4px; display: flex; align-items: center; justify-content: center; font-size: 50px; margin-bottom: 12px; position: relative; transition: 0.2s; }
.product-card:hover .product-img { background: #fdf2f8; }
.sale-badge { position: absolute; top: 12px; left: 12px; background: #ec4899; color: white; font-size: 11px; font-weight: 800; padding: 4px 10px; border-radius: 999px; }
.product-card h3 { font-size: 14.5px; font-weight: 700; margin-bottom: 4px; }
.price-row { display: flex; gap: 8px; align-items: baseline; }
.price { font-size: 14px; font-weight: 800; }
.old-price { font-size: 12.5px; color: #bbb; text-decoration: line-through; }
.cart-drawer { position: fixed; top: 0; right: -380px; width: 360px; height: 100%; background: white; box-shadow: -10px 0 40px rgba(0,0,0,0.1); z-index: 20; transition: right 0.3s; display: flex; flex-direction: column; }
.cart-drawer.open { right: 0; }
.cart-header { display: flex; justify-content: space-between; align-items: center; padding: 24px; border-bottom: 1px solid #f0f0f0; }
.cart-header h2 { font-size: 18px; font-weight: 800; }
.cart-header button { background: none; border: none; font-size: 18px; cursor: pointer; }
.cart-items { flex: 1; overflow-y: auto; padding: 16px 24px; display: flex; flex-direction: column; gap: 14px; }
.cart-item { display: flex; gap: 14px; align-items: center; }
.cart-item-img { width: 60px; height: 60px; background: #f7f7f7; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 24px; flex-shrink: 0; }
.cart-item-info { flex: 1; }
.cart-item-info h4 { font-size: 13.5px; font-weight: 700; }
.cart-item-info span { font-size: 12.5px; color: #999; }
.remove-btn { background: none; border: none; color: #bbb; font-size: 14px; cursor: pointer; }
.cart-footer { padding: 24px; border-top: 1px solid #f0f0f0; }
.cart-total { display: flex; justify-content: space-between; font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.3); display: none; z-index: 19; }
.overlay.show { display: block; }
@media (max-width: 900px) { .navbar, .hero, .products { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 30px; } .cart-drawer { width: 100%; right: -100%; } }

