const products = [
  { id: 1, name: 'Çiçek Desenli Elbise', cat: 'dress', price: 899, oldPrice: 1299, emoji: '👗', sale: true },
  { id: 2, name: 'Keten Bluz', cat: 'top', price: 549, emoji: '👚' },
  { id: 3, name: 'Deri Kemer', cat: 'accessory', price: 349, emoji: '👜' },
  { id: 4, name: 'Maxi Elbise', cat: 'dress', price: 1099, emoji: '👗' },
  { id: 5, name: 'Crop Top', cat: 'top', price: 399, oldPrice: 599, emoji: '👕', sale: true },
  { id: 6, name: 'İpek Eşarp', cat: 'accessory', price: 449, emoji: '🧣' },
  { id: 7, name: 'Yazlık Elbise', cat: 'dress', price: 799, emoji: '👗' },
  { id: 8, name: 'Güneş Gözlüğü', cat: 'accessory', price: 599, emoji: '🕶️' }
];

let cart = [];

function renderProducts(filter) {
  const grid = document.getElementById('productGrid');
  grid.innerHTML = '';
  products
    .filter(p => filter === 'all' || p.cat === filter)
    .forEach(p => {
      const card = document.createElement('div');
      card.className = 'product-card';
      card.innerHTML = `
        <div class="product-img">${p.emoji}${p.sale ? '<span class="sale-badge">İndirim</span>' : ''}</div>
        <h3>${p.name}</h3>
        <div class="price-row">
          <span class="price">₺${p.price}</span>
          ${p.oldPrice ? `<span class="old-price">₺${p.oldPrice}</span>` : ''}
        </div>
      `;
      card.addEventListener('click', () => addToCart(p));
      grid.appendChild(card);
    });
}

function filterProducts(btn, filter) {
  document.querySelectorAll('.filter').forEach(f => f.classList.remove('active'));
  btn.classList.add('active');
  renderProducts(filter);
}

function addToCart(product) {
  cart.push(product);
  updateCart();
  toggleCart(true);
}

function removeFromCart(index) {
  cart.splice(index, 1);
  updateCart();
}

function updateCart() {
  document.getElementById('cartCount').textContent = cart.length;
  const itemsContainer = document.getElementById('cartItems');
  itemsContainer.innerHTML = '';
  let total = 0;
  cart.forEach((item, i) => {
    total += item.price;
    const div = document.createElement('div');
    div.className = 'cart-item';
    div.innerHTML = `
      <div class="cart-item-img">${item.emoji}</div>
      <div class="cart-item-info"><h4>${item.name}</h4><span>₺${item.price}</span></div>
      <button class="remove-btn" onclick="removeFromCart(${i})">✕</button>
    `;
    itemsContainer.appendChild(div);
  });
  document.getElementById('cartTotal').textContent = `₺${total}`;
}

function toggleCart(forceOpen) {
  const drawer = document.getElementById('cartDrawer');
  const overlay = document.getElementById('overlay');
  const shouldOpen = forceOpen !== undefined ? forceOpen : !drawer.classList.contains('open');
  drawer.classList.toggle('open', shouldOpen);
  overlay.classList.toggle('show', shouldOpen);
}

renderProducts('all');
